import{_ as s,c as e,o as n,ae as t}from"./chunks/framework.Dh1jimFm.js";const u=JSON.parse('{"title":"前端Vue单元测试入门","description":"","frontmatter":{},"headers":[],"relativePath":"document/UnitTest/UnitTest.md","filePath":"document/UnitTest/UnitTest.md"}'),i={name:"document/UnitTest/UnitTest.md"};function p(l,a,o,c,r,d){return n(),e("div",null,a[0]||(a[0]=[t(`<h1 id="前端vue单元测试入门" tabindex="-1">前端Vue单元测试入门 <a class="header-anchor" href="#前端vue单元测试入门" aria-label="Permalink to &quot;前端Vue单元测试入门&quot;">​</a></h1><p><a href="https://juejin.cn/post/7030781955494903844?searchId=20230807192651EECFDBEAFB046614E73E" target="_blank" rel="noreferrer">https://juejin.cn/post/7030781955494903844?searchId=20230807192651EECFDBEAFB046614E73E</a></p><h2 id="为什么需要单元测试" tabindex="-1">为什么需要单元测试 <a class="header-anchor" href="#为什么需要单元测试" aria-label="Permalink to &quot;为什么需要单元测试&quot;">​</a></h2><p>单元测试是用来测试项目中的一个模块的功能，如函数、类、组件等。单元测试的作用有以下：</p><ul><li>正确性：可以验证代码的正确性，为上线前做更详细的准备；</li><li>自动化： 测试用例可以整合到代码版本管理中，自动执行单元测试，避免每次手工操作；</li><li>解释性：能够为其他开发人员提供被测模块的文档参考，阅读测试用例可能比文档更完善；</li><li>驱动开发、指导设计：提前写好的单元测试能够指导开发的API设计，也能够提前发现设计中的问题；</li><li>保证重构：测试用例可以多次验证，当需要回归测试时能够节省大量时间。</li></ul><h2 id="如何写单元测试" tabindex="-1">如何写单元测试 <a class="header-anchor" href="#如何写单元测试" aria-label="Permalink to &quot;如何写单元测试&quot;">​</a></h2><h3 id="测试原则" tabindex="-1">测试原则 <a class="header-anchor" href="#测试原则" aria-label="Permalink to &quot;测试原则&quot;">​</a></h3><ul><li>测试代码时，只考虑测试，不考虑内部实现；</li><li>数据尽量模拟现实，越靠近现实越好；</li><li>充分考虑数据的边界条件；</li><li>对重点、复杂、核心代码，重点测试；</li><li>测试、功能开发相结合，有利于设计和代码重构。</li></ul><h3 id="编写步骤" tabindex="-1">编写步骤 <a class="header-anchor" href="#编写步骤" aria-label="Permalink to &quot;编写步骤&quot;">​</a></h3><p>1.准备阶段：构造参数，创建spy等； 2.执行阶段：用构造好的参数执行被测试代码； 3.断言阶段：用实际得到的结果与期望的结果比较，以判断该测试是否正常； 4.清理阶段：清理准备阶段对外部环境的影响，移除在准备阶段创建的spy等。</p><h2 id="测试工具" tabindex="-1">测试工具 <a class="header-anchor" href="#测试工具" aria-label="Permalink to &quot;测试工具&quot;">​</a></h2><p>单元测试的工具可分为三类：</p><ul><li>测试运行器：可以模拟各种浏览器环境，自定义配置测试框架和断言库等，如Karma</li><li>测试框架：提供单元测试的功能模块，常见的框架有Jest、mocha、Jasmine、QUnit；</li><li>工具库：assert、should.js、expect.js、chai.js等断言库，enzyme渲染库，lstanbul覆盖率计算。</li></ul><p>Jest比较常用。Jest功能全面，集成了各种工具，且配置简单，甚至零配置直接使用。</p><h2 id="jest" tabindex="-1">Jest <a class="header-anchor" href="#jest" aria-label="Permalink to &quot;Jest&quot;">​</a></h2><h3 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-label="Permalink to &quot;安装&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>yarn add --dev jest</span></span>
<span class="line"><span># or</span></span>
<span class="line"><span># npm install -D jest</span></span></code></pre></div><h3 id="简单示例" tabindex="-1">简单示例 <a class="header-anchor" href="#简单示例" aria-label="Permalink to &quot;简单示例&quot;">​</a></h3><p>创建文件sum.js</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>function sum(a, b) {</span></span>
<span class="line"><span>  return a + b;</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>module.exports = sum;</span></span></code></pre></div><p>创建sum.test.js文件</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>const sum = require(&#39;./sum&#39;);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>test(&#39;adds 1 + 2 to equal 3&#39;, () =&gt; {</span></span>
<span class="line"><span>  expect(sum(1, 2)).toBe(3);</span></span>
<span class="line"><span>});</span></span></code></pre></div><p>在package.json中添加测试任务</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>{</span></span>
<span class="line"><span>  &quot;scripts&quot;: {</span></span>
<span class="line"><span>    &quot;test&quot;: &quot;jest&quot;</span></span>
<span class="line"><span>  }</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>最后，运行 yarn test 或 npm run test ，Jest将打印下面这个消息：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PASS  ./sum.test.js</span></span>
<span class="line"><span>✓ adds 1 + 2 to equal 3 (5ms)</span></span></code></pre></div><p>至此 完成了一个基本的单元测试。</p><p>注意：Jest 通过用 JSDOM 在 Node 虚拟浏览器环境模拟真实浏览器，由于是用 js 模拟 DOM, 所以 Jest 无法测试样式 。Jest 测试运行器自动设置了 JSDOM。</p>`,28)]))}const b=s(i,[["render",p]]);export{u as __pageData,b as default};
